[cite_start]trainline/uk_single/0,"{""_target_"": ""navi_bench.trainline.trainline_url_match.generate_task_config_deterministic"", ""task"": ""I have a crucial client presentation in Manchester tomorrow — well, not tomorrow, on {outDate}. I need to get there from London Euston. Just me, one adult. One-way ticket. What are the cheapest standard fares available? I don't need first class, but tell me both standard and first class prices for comparison."", ""queries"": [[""[https://www.thetrainline.com/book/results?journeySearchType=single&origin=urn:trainline:generic:loc:EUS1444gb&destination=urn:trainline:generic:loc:MAN2968gb&outwardDate=](https://www.thetrainline.com/book/results?journeySearchType=single&origin=urn:trainline:generic:loc:EUS1444gb&destination=urn:trainline:generic:loc:MAN2968gb&outwardDate=){outDate}T12:00:00&outwardDateType=departAfter""]], ""passenger_summary_scraped"": ""1 adult"", ""origin_station"": ""London Euston"", ""destination_station"": ""Manchester Piccadilly"", ""location"": ""United Kingdom"", ""timezone"": ""Europe/London"", ""timestamp"": null, ""values"": {""outDate"": ""{now() + timedelta(14)}""}}",real,trainline,travel,trains,hard,Uses deterministic query structure with scraped passenger summary.[cite: 49, 148],50,validation,{}
